PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?actor ?age
WHERE {
  VALUES ?actor { wd:Q701940 wd:Q7967036 wd:Q3110914 wd:Q9455990 wd:Q7608613 wd:Q709655 wd:Q1200110 wd:Q5354246 wd:Q7244051 }
  ?actor wdt:P106 wd:Q1274260 .
  ?series p:P161 ?statement ;
          wdt:P123 wd:Q5952 ;
          wdt:P577 ?date .
  ?statement ps:P161 ?actor .
  FILTER (YEAR(?date) = 1999)
  ?actor wdt:P569 ?birth .
  ?actor wdt:P570 ?death .
  FILTER (BOUND(?death))
  BIND (YEAR(?death) - YEAR(?birth) AS ?age)
}

